-- ============================================================
-- 11. 현금 출납 (20건)
-- ============================================================

-- 완료 메시지
select '더미 데이터 삽입 완료!' as result,
  (select count(*) from businesses) as 사업자수,
  (select count(*) from channels) as 채널수,
  (select count(*) from warehouses) as 창고수,
  (select count(*) from partners) as 거래처수,
  (select count(*) from products) as 상품수,
  (select count(*) from inventory) as 재고항목수,
  (select count(*) from slips) as 전표수,
  (select count(*) from slip_items) as 전표품목수,
  (select count(*) from cash_book) as 현금출납수;
